 1	import type { FC } from 'react';
 2	import { TableCell } from 'src/modules/Providers/utils/components/TableCell/TableCell';
 3	
 4	import { Label } from '@patternfly/react-core';
 5	
 6	import { getOpenShiftFeatureMap } from '../utils/helpers/getOpenShiftFeatureMap';
 7	import { toVmFeatureEnum } from '../utils/helpers/toVmFeatureEnum';
 8	
 9	import type { VMCellProps } from './VMCellProps';
10	
11	export const VmFeaturesCell: FC<VMCellProps> = ({ data }) => {
12	  const featureToLabel = toVmFeatureEnum();
13	  return (
14	    <TableCell>
15	      {Object.entries(getOpenShiftFeatureMap(data?.vm))
16	        .filter(([, value]) => value)
17	        .map(([key]) => (
18	          <Label key={key} isCompact>
19	            {featureToLabel[key]}
20	          </Label>
21	        ))}
22	    </TableCell>
23	  );
24	};

